import{c as e,Q as t,j as s,m as i}from"./chunks/framework.DVkeSyfh.js";const h=JSON.parse('{"title":"Tags and audio writes","description":"","frontmatter":{},"headers":[],"relativePath":"ru/user-guide/tags-and-audio-writes.md","filePath":"ru/user-guide/tags-and-audio-writes.md","lastUpdated":null}'),r={name:"ru/user-guide/tags-and-audio-writes.md"};function o(d,a,l,n,p,c){return t(),s("div",null,[...a[0]||(a[0]=[i('<h1 id="tags-and-audio-writes" tabindex="-1">Tags and audio writes <a class="header-anchor" href="#tags-and-audio-writes" aria-label="Permalink to &quot;Tags and audio writes&quot;">​</a></h1><p>Аудитория: осторожные пользователи и power users<br> Цель: понять явное исключение для tag writing<br> Тип: how-to</p><p>Большинство app workflows read-only по отношению к source audio. Genre tag writing - намеренное исключение: оно может записать stored MAEST genre labels в standard audio genre tags.</p><h2 id="что-может-писать-tags" tabindex="-1">Что может писать tags <a class="header-anchor" href="#что-может-писать-tags" aria-label="Permalink to &quot;Что может писать tags&quot;">​</a></h2><p>Явный app path:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>POST /api/tags/genres/apply</span></span></code></pre></div><p>или соответствующий UI job.</p><p>Он пишет только standard genre field из stored MAEST labels. Title, artist, album, BPM, key и другие normal tags должны сохраняться.</p><h2 id="formats" tabindex="-1">Formats <a class="header-anchor" href="#formats" aria-label="Permalink to &quot;Formats&quot;">​</a></h2><p>Tag-writing code использует standard fields:</p><ul><li><code>TCON</code> for MP3/WAV/AIFF ID3;</li><li><code>GENRE</code> for FLAC/Vorbis-style tags;</li><li><code>©gen</code> for MP4/M4A/ALAC.</li></ul><h2 id="batch-behavior" tabindex="-1">Batch behavior <a class="header-anchor" href="#batch-behavior" aria-label="Permalink to &quot;Batch behavior&quot;">​</a></h2><p>Failed writes должны fail только этот track и позволить batch продолжиться. Для WAV app использует Mutagen WAVE/ID3 handling и read back <code>TCON</code>; custom RIFF repair logic не добавляется в tag-writing path.</p><h2 id="перед-записью-tags" tabindex="-1">Перед записью tags <a class="header-anchor" href="#перед-записью-tags" aria-label="Permalink to &quot;Перед записью tags&quot;">​</a></h2><p>Убедитесь, что:</p><ul><li>MAEST labels есть и их стоит записывать;</li><li>у вас есть backups, если файлы важны;</li><li>вы понимаете, что это не search, analysis, preview или export.</li></ul>',16)])])}const g=e(r,[["render",o]]);export{h as __pageData,g as default};
